// REPLACE readEventLedger body with tail-tolerant version:
export async function readEventLedger(projectRoot, options = {}): Promise<{events: StoredEventLedgerEvent[], warnings: LedgerWarning[]}> {
  const eventPath = getEventLedgerPath(projectRoot);
  let raw: string;
  try { raw = await readFile(eventPath, 'utf8'); } catch (e) {
    if (isNodeError(e) && e.code === 'ENOENT') return { events: [], warnings: [] };
    throw e;
  }
  // Drop trailing partial line: the last segment after split is empty if file ends with \n.
  // If non-empty (no trailing newline), check JSON validity; if invalid, treat as PARTIAL (recoverable).
  const segments = raw.split(/\r?\n/);
  const trailingPartial = segments.length > 0 && segments[segments.length - 1].length > 0 && raw[raw.length - 1] !== '\n';
  const lines = trailingPartial ? segments.slice(0, -1) : segments;
  const tail = trailingPartial ? segments[segments.length - 1] : null;
  const warnings: LedgerWarning[] = [];
  if (tail !== null) {
    // Validate the tail; if it's actually valid JSON+schema, KEEP IT (file just lacks newline). Else flag as partial-write.
    const validated = tryParseLine(tail);
    if (validated !== null) lines.push(tail);
    else warnings.push({ kind: 'partial_tail', byteOffset: raw.length - tail.length, length: tail.length });
  }
  const events: StoredEventLedgerEvent[] = [];
  for (let i = 0; i < lines.length; i++) {
    const line = lines[i].trim();
    if (line.length === 0) continue;
    const parsed = parseEventLedgerLine(line, i);
    if (parsed === null) {
      warnings.push({ kind: 'invalid_line', lineNumber: i + 1, snippet: line.slice(0, 120) });
      continue;
    }
    events.push(parsed);
  }
  return { events: applyFilters(events, options), warnings };
}

