// New helper alongside ensureEventLedger (~L671):
async function truncateLedgerToLastNewline(projectRoot: string): Promise<void> {
  const path = getEventLedgerPath(projectRoot);
  const raw = await readFile(path, 'utf8');
  const lastNewline = raw.lastIndexOf('\n');
  if (lastNewline === -1) {
    // No complete line at all — back up to .corrupted and create empty.
    await rename(path, `${path}.${Date.now()}.corrupted`);
    await writeFile(path, '', { encoding: 'utf8' });
    return;
  }
  const safe = raw.slice(0, lastNewline + 1);
  // Use atomicWriteText to avoid creating a SECOND partial state during rewrite.
  await atomicWriteText(path, safe);
}
//
// SIDE EFFECT: emit a fabric-event of event_type 'event_ledger_truncated' AFTER the rewrite,
// so the ledger contains a self-describing record of what was lost (byte range, timestamp).

