// REPLACE startStdioServer body with:
export async function startStdioServer(): Promise<void> {
  const server = createFabricServer();
  const transport = new StdioServerTransport();
  const tracker = createInFlightTracker(); // see in_flight_tracking below
  installRequestTrackingMiddleware(server, tracker); // wraps each tool/resource handler
  await server.connect(transport);
  installShutdownHandlers({ server, transport, tracker });
}

function installShutdownHandlers(opts: {
  server: McpServer;
  transport: StdioServerTransport;
  tracker: InFlightTracker;
}): void {
  const SHUTDOWN_DEADLINE_MS = 5000;
  let shuttingDown = false;

  const handle = (signal: NodeJS.Signals) => {
    if (shuttingDown) {
      // Second signal = hard exit.
      writeStderr(`Received ${signal} during shutdown — forcing exit.`);
      process.exit(130); // 128+2 for SIGINT, but okay as a 'forced' marker.
    }
    shuttingDown = true;
    writeStderr(`Received ${signal} — draining ${opts.tracker.size()} in-flight request(s).`);

    const deadline = setTimeout(() => {
      writeStderr(`Shutdown deadline (${SHUTDOWN_DEADLINE_MS}ms) reached — forcing exit.`);
      process.exit(1);
    }, SHUTDOWN_DEADLINE_MS);
    deadline.unref();

    void (async () => {
      try {
        await opts.tracker.waitForDrain();
        await opts.transport.close(); // closes stdin/stdout reader
        // McpServer.close is not in current SDK; transport close is sufficient.
        process.exit(0);
      } catch (error) {
        writeStderr(formatError(error));
        process.exit(1);
      }
    })();
  };

  process.on('SIGINT', handle);
  process.on('SIGTERM', handle);
  process.on('SIGHUP', handle);
}

// In-flight tracker (~20 LOC):
interface InFlightTracker {
  begin(): () => void;
  size(): number;
  waitForDrain(): Promise<void>;
}
function createInFlightTracker(): InFlightTracker {
  let pending = new Set<symbol>();
  let drainResolvers: Array<() => void> = [];
  return {
    begin() {
      const token = Symbol();
      pending.add(token);
      return () => {
        pending.delete(token);
        if (pending.size === 0) {
          for (const r of drainResolvers) r();
          drainResolvers = [];
        }
      };
    },
    size: () => pending.size,
    waitForDrain: () => pending.size === 0
      ? Promise.resolve()
      : new Promise<void>(resolve => drainResolvers.push(resolve)),
  };
}

